    uint8_t tdmaSlot = 0;
    bool tdmaSlotKnown = false;
    bool p25MaskParamsKnown = false;
    uint16_t nac = 0;
    uint32_t wacn = 0;
    uint16_t systemId = 0;
    uint8_t rfssId = 0;
    uint8_t siteId = 0;
    int hitCount = 0;
    bool encryptionKnown = false;
    bool encrypted = false;
    bool verified = false;
